from collections import defaultdict

# Define a DFA as a tuple (states, alphabet, transition, start_state, accept_states)
# Language 1: Strings ending with 'ab' (accepts 'ab', 'aab', 'bab', etc.)
dfa1 = {
    'states': {'q0', 'q1', 'q2'},
    'alphabet': {'a', 'b'},
    'transition': {
        ('q0', 'a'): 'q1',
        ('q0', 'b'): 'q0',
        ('q1', 'a'): 'q1',
        ('q1', 'b'): 'q2',
        ('q2', 'a'): 'q1',
        ('q2', 'b'): 'q0'
    },
    'start_state': 'q0',
    'accept_states': {'q2'}
}

# Language 2: Strings containing 'ba' as substring (accepts 'ba', 'aba', 'bba', etc.)
dfa2 = {
    'states': {'p0', 'p1'},
    'alphabet': {'a', 'b'},
    'transition': {
        ('p0', 'a'): 'p0',
        ('p0', 'b'): 'p1',
        ('p1', 'a'): 'p1',
        ('p1', 'b'): 'p1'
    },
    'start_state': 'p0',
    'accept_states': {'p1'}
}

def simulate_dfa(dfa, input_string):
    """Check if DFA accepts the input string."""
    current_state = dfa['start_state']
    for symbol in input_string:
        current_state = dfa['transition'].get((current_state, symbol))
        if current_state is None:
            return False
    return current_state in dfa['accept_states']

def dfa_union(dfa1, dfa2):
    """Construct DFA for L(dfa1) U L(dfa2) using product construction."""
    states = [(s1, s2) for s1 in dfa1['states'] for s2 in dfa2['states']]
    start = (dfa1['start_state'], dfa2['start_state'])
    accept = {(s1, s2) for s1 in dfa1['states'] for s2 in dfa2['states']
              if s1 in dfa1['accept_states'] or s2 in dfa2['accept_states']}

    transition = {}
    for (s1, s2) in states:
        for symbol in dfa1['alphabet']:
            t1 = dfa1['transition'].get((s1, symbol), s1)
            t2 = dfa2['transition'].get((s2, symbol), s2)
            transition[(s1, s2, symbol)] = (t1, t2)

    return {'states': set(states), 'alphabet': dfa1['alphabet'],
            'transition': transition, 'start_state': start, 'accept_states': accept}

def dfa_intersection(dfa1, dfa2):
    """Construct DFA for L(dfa1) ∩ L(dfa2) using product construction."""
    states = [(s1, s2) for s1 in dfa1['states'] for s2 in dfa2['states']]
    start = (dfa1['start_state'], dfa2['start_state'])
    accept = {(s1, s2) for s1 in dfa1['states'] for s2 in dfa2['states']
              if s1 in dfa1['accept_states'] and s2 in dfa2['accept_states']}

    transition = {}
    for (s1, s2) in states:
        for symbol in dfa1['alphabet']:
            t1 = dfa1['transition'].get((s1, symbol), s1)
            t2 = dfa2['transition'].get((s2, symbol), s2)
            transition[(s1, s2, symbol)] = (t1, t2)

    return {'states': set(states), 'alphabet': dfa1['alphabet'],
            'transition': transition, 'start_state': start, 'accept_states': accept}

# Test the closure properties
test_strings = ['', 'ab', 'ba', 'aab', 'aba', 'bab', 'baba', 'aaab']

print("String\t\tEnds 'ab'\tContains 'ba'\tUnion\tIntersection")
print("-" * 65)
for s in test_strings:
    r1 = simulate_dfa(dfa1, s)
    r2 = simulate_dfa(dfa2, s)
    union_dfa = dfa_union(dfa1, dfa2)
    inter_dfa = dfa_intersection(dfa1, dfa2)
    ru = simulate_dfa(union_dfa, s)
    ri = simulate_dfa(inter_dfa, s)
    print(f"'{s}'\t\t{r1}\t\t{r2}\t\t{ru}\t\t{ri}")

from collections import deque

class DFA:
    def __init__(self, states, alphabet, transition, start_state, accept_states):
        self.states = states
        self.alphabet = alphabet
        self.transition = transition
        self.start_state = start_state
        self.accept_states = accept_states

    def accepts(self, input_string):
        current = self.start_state
        for symbol in input_string:
            if (current, symbol) not in self.transition:
                return False
            current = self.transition[(current, symbol)]
        return current in self.accept_states

    def is_empty(self):
        """Check if language is empty (no accept states reachable from start)."""
        reachable = self._reachable_states()
        return reachable.isdisjoint(self.accept_states)

    def is_finite(self):
        """Check if language is finite using BFS to detect cycles in accepting states."""
        reachable = self._reachable_states()
        accepting_reachable = reachable & self.accept_states

        # If no accepting states reachable, language is empty (finite)
        if not accepting_reachable:
            return True

        # Build graph and check for cycles reachable from start that can reach accepting states
        graph = defaultdict(set)
        for (state, symbol), next_state in self.transition.items():
            graph[state].add(next_state)

        # Find states that can reach accepting states (reverse reachability)
        can_reach_accept = self._reverse_reachable(accepting_reachable)

        # Check for cycles in the subgraph of states that can reach accept
        visited = set()
        rec_stack = set()

        def has_cycle(state):
            visited.add(state)
            rec_stack.add(state)
            for neighbor in graph[state]:
                if neighbor in can_reach_accept:
                    if neighbor not in visited:
                        if has_cycle(neighbor):
                            return True
                    elif neighbor in rec_stack:
                        return True
            rec_stack.remove(state)
            return False

        for state in can_reach_accept:
            if state not in visited:
                if has_cycle(state):
                    return False  # Language is infinite
        return True

    def _reachable_states(self):
        """Find all states reachable from start state."""
        reachable = {self.start_state}
        queue = deque([self.start_state])

        while queue:
            state = queue.popleft()
            for symbol in self.alphabet:
                next_state = self.transition.get((state, symbol))
                if next_state and next_state not in reachable:
                    reachable.add(next_state)
                    queue.append(next_state)
        return reachable

    def _reverse_reachable(self, target_states):
        """Find all states that can reach any target state."""
        # Build reverse graph
        reverse_graph = defaultdict(set)
        for (state, symbol), next_state in self.transition.items():
            reverse_graph[next_state].add(state)

        reachable = set(target_states)
        queue = deque(target_states)

        while queue:
            state = queue.popleft()
            for prev in reverse_graph[state]:
                if prev not in reachable:
                    reachable.add(prev)
                    queue.append(prev)
        return reachable

# Example: DFA for (a|b)*a (strings ending with 'a')
dfa_finite = DFA(
    states={'q0', 'q1'},
    alphabet={'a', 'b'},
    transition={
        ('q0', 'a'): 'q1', ('q0', 'b'): 'q0',
        ('q1', 'a'): 'q1', ('q1', 'b'): 'q0'
    },
    start_state='q0',
    accept_states={'q1'}
)

# Example: DFA for a*b* (infinite language - has a cycle)
dfa_infinite = DFA(
    states={'s'},
    alphabet={'a', 'b'},
    transition={('s', 'a'): 's', ('s', 'b'): 's'},
    start_state='s',
    accept_states={'s'}
)

# Example: DFA for exactly 'ab' (finite language - no cycles)
dfa_exact = DFA(
    states={'r0', 'r1', 'r2', 'r3'},
    alphabet={'a', 'b'},
    transition={
        ('r0', 'a'): 'r1', ('r0', 'b'): 'r3',
        ('r1', 'a'): 'r3', ('r1', 'b'): 'r2',
        ('r2', 'a'): 'r3', ('r2', 'b'): 'r3',
        ('r3', 'a'): 'r3', ('r3', 'b'): 'r3'
    },
    start_state='r0',
    accept_states={'r2'}
)

print("=== Decision Properties Demo ===\n")

# Test membership
test_cases = ['', 'a', 'b', 'ab', 'ba', 'aab', 'abb']
print("Membership Testing for DFA (ending with 'a'):")
for s in test_cases:
    print(f"  '{s}' -> {dfa_finite.accepts(s)}")

print("\n--- Emptiness Check ---")
print(f"Language ending with 'a': Empty? {dfa_finite.is_empty()}")
print(f"Language a*b*: Empty? {dfa_infinite.is_empty()}")
print(f"Language exactly 'ab': Empty? {dfa_exact.is_empty()}")

print("\n--- Finiteness Check ---")
print(f"Language ending with 'a': Finite? {dfa_finite.is_finite()}")
print(f"Language a*b*: Finite? {dfa_infinite.is_finite()}")
print(f"Language exactly 'ab': Finite? {dfa_exact.is_finite()}")
